local IdentityCaches = {}
local EnableIdentityEffect = true

PlayerIdentityCache = {}

function PlayerIdentityCache:init()
    WebService:GetPlayerIdentityCache(function (data)
        if not data then
            return
        end
        IdentityCaches = data
    end)
end

---添加玩家身份标识到分段列表里
---@param userId number 玩家userId
---@param nameList table 玩家名字分段列表
---@param name string 玩家原昵称
---@param namePrefix string 玩家昵称前缀
function PlayerIdentityCache:buildNameList(userId, nameList, name, namePrefix)
    namePrefix = namePrefix or ""
    local cache = IdentityCaches[tostring(userId)]
    if not cache then
        table.insert(nameList, namePrefix .. TextFormat.colorWrite .. name)
        return
    end
    if cache.GameType ~= nil then
        local needRebuild = false
        local gameTypes = StringUtil.split(cache.GameType, ",")
        for _, gameType in pairs(gameTypes) do
            if gameType == "all" or gameType == BaseMain:getGameType() then
                needRebuild = true
                break
            end
        end
        if not needRebuild then
            table.insert(nameList, namePrefix .. TextFormat.colorWrite .. name)
            return
        end
    end
    if cache.TitlePlus ~= nil then
        table.insert(nameList, cache.TitlePlus .. TextFormat.colorEnd)
    end
    if cache.Title ~= nil then
        table.insert(nameList, cache.Title .. TextFormat.colorEnd)
    end
    if cache.NameColor ~= nil then
        table.insert(nameList, namePrefix .. cache.NameColor .. name .. TextFormat.colorEnd)
    else
        table.insert(nameList, namePrefix .. TextFormat.colorWrite .. name)
    end
end

function PlayerIdentityCache:disableIdentityEffect()
    EnableIdentityEffect = false
end

function PlayerIdentityCache:onPlayerSpawn(player)
    if not EnableIdentityEffect then
        return
    end
    local cache = IdentityCaches[tostring(player.userId)]
    if not cache then
        return
    end
    if cache.GameType ~= nil then
        local needRebuild = false
        local gameTypes = StringUtil.split(cache.GameType, ",")
        for _, gameType in pairs(gameTypes) do
            if gameType == "all" or gameType == BaseMain:getGameType() then
                needRebuild = true
                break
            end
        end
        if not needRebuild then
            return
        end
    end
    if cache.Effect ~= nil and #cache.Effect > 7 then
        player:addCustomEffect("IdentityEffect", cache.Effect, -1, 1)
    end
    if cache.EffectPlus ~= nil and #cache.EffectPlus > 7 then
        player:addCustomEffect("IdentityEffectPlus", cache.EffectPlus, -1, 1)
    end
end